module RefModule (clk, rst, en, data_in, q);
   input clk, rst, en, data_in;
   output reg [7:0] q;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
      if (rst)
         q <= 8'b00000000;
      else if (en)
         q <= {q[6:0], data_in};
   end
endmodule
